-- 正常订单 is_violation:是否违约（01正常，02结算单逾期，\n03提前归还，04 账单逾期） -- '订单状态 01:待支付 02:支付中 03:已支付申请关单 04:待发货 05:待确认收货 06:租用中 07:待结算 08:结算待支付 09:订单完成 10:交易关闭 12待归还 13下单待审核 14申请取消 15商家关单', SELECT order_id,channel_provenance FROM llxz_order.ct_user_orders where channel_provenance <>2 LIMIT 1; SELECT * FROM llxz_order.ct_user_orders where order_id='008OI202603242036289731008229376T'; select * from llxz_order.ct_order_by_stages_ext where order_id='008OI202602142022604732018507776T' -- 订单扩展表
