-- '状态: 1：待支付 2：已支付 3：逾期已支付 4：逾期待支付 5：已取消 6: 已结算 7:已退款' SELECT * FROM llxz_order.ct_order_by_stages where order_id='008OI202604092042160772696559616T' LIMIT 15; -- 查询账期时间三天内、账期日是0点的账单数据 select distinct order_id, statement_date,create_time from llxz_order.ct_order_by_stages where create_time between '2026-03-02 12:00:00'-INTERVAL 3 DAY and '2026-03-02 12:00:00' and statement_date like '%00:00:00%'; -- -- 所有的支付宝交互都查这张表 SELECT * FROM `llxz_components`.ct_alipay_commerce_rent_order WHERE order_id = '2025112701502300000009930001807558' LIMIT 10; --租赁订单支付请求记录 可通过交易流水号查看平台订单号 SELECT * from `llxz_components`.ct_alipay_commerce_rent_order_pay WHERE `trade_no`='2025112722001471991433403332' LIMIT 1;
