-- 商品下架 -- type 0回收站中的商品 1已上架售卖的商品 2放在仓库的商品 -- common_status 公域状态, 3 公域显示 ,4 公域隐藏 -- status 商品状态 0为失效 1为有效 -- shop_status 0失效 1有效 -- hide 上架不显示 0否 1是 -- all_hide 公域隐藏 0否 1是 -- audit_state 商品审核状态 0为正在审核中 1为审核不通过 2为审核通过 SELECT t.create_time, t.update_time, t.delete_time, t.category_id, t.`type`, t.common_status, t.status, t.shop_id, t.shop_status, t.audit_state, product_color_picture FROM llxz_product.ct_product t where product_id = '1623308580547'
-- operate_category_id 分类Id -- parent_category_id 父类id -- status 0失效 1有效 -- hide 隐藏 -- all_hide 公域隐藏 select t.update_time, t.delete_time, t.operate_category_id, t.parent_category_id, t.status, t.hide, t.all_hide, t.enjoy_first from llxz_product.ct_ope_category_product t where t.item_id = '1623308580547'
select group_CONCAT('"', t.product_id, '"') from (
select t.product_id from llxz_product.ct_product t where t.audit_state = 2 and t.delete_time is null ) t
SELECT cobs.order_id, cobs.current_periods AS currentPeriods, cobs.current_periods_rent AS periodAmount FROM llxz_order.ct_user_orders AS cuo INNER JOIN llxz_order.ct_order_by_stages AS cobs ON cobs.order_id = cuo.order_id WHERE cobs.statement_date BETWEEN '2025-06-26 00:00:00' AND '2025-06-26 23:59:59' AND cobs.STATUS = 1 AND cuo.STATUS = '06' AND cuo.is_violation IN ('01', '03') AND cobs.shop_id = '2024082807241574431724844255789' GROUP BY cobs.order_id;
-- 查询明日到期的订单 SELECT cobs.order_id, cobs.current_periods AS currentPeriods, cobs.current_periods_rent AS periodAmount FROM llxz_order.ct_user_orders AS cuo INNER JOIN llxz_order.ct_order_by_stages AS cobs ON cobs.order_id = cuo.order_id WHERE DATE_SUB(cobs.statement_date, INTERVAL 1 DAY) BETWEEN '2025-06-25 00:00:00' AND '2025-06-25 23:59:59' AND cobs.STATUS IN (1) AND cuo.STATUS IN ('06') AND cuo.is_violation IN ('01', '03') AND cobs.shop_id = '2024082807241574431724844255789' GROUP BY cobs.order_id
