SELECT cos.* FROM llxz_order.ct_user_orders co INNER JOIN llxz_order.ct_order_by_stages cos ON co.order_id = cos.order_id WHERE cos.`status` IN (1,4) AND cos.debit_status = '1' AND co.type in ('11','12','13','14','15') AND cos.statement_date < '2026-03-25 23:59:59' AND cos.order_id IN ( SELECT DISTINCT cos1.order_id FROM llxz_order.ct_user_orders co1 INNER JOIN llxz_order.ct_order_by_stages cos1 ON co1.order_id = cos1.order_id WHERE cos1.`status` IN (1,4) AND cos1.debit_status = '1' AND co1.`status` = '06' AND co1.type in ('11','12','13','14','15') AND cos1.statement_date BETWEEN '2025-07-25 23:59:59' AND '2026-03-25 23:59:59' AND co1.id > 12105649 ) AND NOT EXISTS ( SELECT 1 FROM llxz_order.ct_order_by_stages cos2 WHERE cos2.order_id = cos.order_id AND cos2.`status` IN (1,4) AND cos2.debit_status = '1' AND cos2.statement_date < '2026-03-25 23:59:59' AND ( cos2.current_periods < cos.current_periods OR (cos2.current_periods = cos.current_periods AND cos2.id < cos.id) ) ) LIMIT 100;
