SELECT DISTINCT cuo.user_name FROM llxz_order.ct_user_orders cuo INNER JOIN llxz_order.ct_order_by_stages cobs ON cobs.order_id = cuo.order_id WHERE cuo.shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' AND cuo.status IN ('06') AND cuo.is_violation = '04' AND (cuo.delete_time IS NULL OR cuo.delete_time <= '2001-01-01 00:00:00') AND cuo.user_name IS NOT NULL AND cobs.statement_date < CURDATE() AND cobs.status = 4 -- 账期状态为待还款 AND cobs.shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' -- 限制账期表的 shop_id ORDER BY cuo.create_time DESC LIMIT 1;

