-- 商品下架 -- type 0回收站中的商品 1已上架售卖的商品 2放在仓库的商品 -- common_status 公域状态, 3 公域显示 ,4 公域隐藏 -- status 商品状态 0为失效 1为有效 -- shop_status 0失效 1有效 -- hide 上架不显示 0否 1是 -- all_hide 公域隐藏 0否 1是 -- audit_state 商品审核状态 0为正在审核中 1为审核不通过 2为审核通过 SELECT t.create_time, t.update_time, t.delete_time, t.category_id, t.`type`, t.common_status, t.status, t.shop_id, t.shop_status, t.audit_state, product_color_picture FROM llxz_product.ct_product t where product_id = '1623308580547'
-- operate_category_id 分类Id -- parent_category_id 父类id -- status 0失效 1有效 -- hide 隐藏 -- all_hide 公域隐藏 select t.update_time, t.delete_time, t.operate_category_id, t.parent_category_id, t.status, t.hide, t.all_hide, t.enjoy_first from llxz_product.ct_ope_category_product t where t.item_id = '1623308580547'
-- 71008738021cd3393bacbac182bd6a86af0b5c87 sass人人享租1 -- 2025041702585837981744873138304 NQ
-- 店铺认证 `type` tinyint(4) DEFAULT NULL COMMENT '企业类型 : 1 个体工商户 2 企业' -- 查询店铺信息 select * from llxz_product.ct_shop where name LIKE '%莫小贝%' select * from llxz_product.ct_shop where `name` like '%sass人人享租1%' -- 绕过验签 select * from llxz_product.ct_shop_enterprise_infos t where t.shop_id = '2025122501531681921766641996005' -- seal_status：签章认证状态 1未认证 2认证失败 3已认证 4重新认证 select * from llxz_product.ct_shop_enterprise_infos t where t.shop_id = '2025121810424137851766025761407' -- seal_status：签章认证状态 1未认证 2认证失败 3已认证 4重新认证 -- 入驻店铺时填写的收货地址 select * from llxz_product.ct_shop_give_back_addresses where shop_id='71008738021cd3393bacbac182bd6a86af0b5c87' -- 快递方式-包邮:FREE 到付:PAY 自提:SELF
