-- 业务单代扣解约 select * from llxz_components.ct_alipayUser_agreement_log a where a.user_id in ('2088102635680708',''); select * from llxz_components.ct_alipayUser_agreement_log a where a.agreement_no ='20255509172925619770'; select * from llxz_components.ct_alipayUser_agreement_log a where a.external_agreement_no='008OI202507081942459003594477568'; SELECT * FROM `ct_alipay_open_mini_order_create` WHERE order_id = '2024072801502300000003740051191939' LIMIT 0, 25; select * from llxz_product.ct_product t where t.shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' and t.audit_state = '3' and t.delete_time is null
-- 商品店铺关联查询 SELECT * FROM llxz_product.ct_product AS p INNER JOIN llxz_product.ct_shop AS s ON p.shop_id = s.shop_id WHERE p.STATUS = 1 AND p.shop_status = 1 AND p.lock_state = 0 AND p.audit_state = 0 LIMIT 1
