-- 查询有效商品 select * from llxz_product.ct_product where audit_state=0 and shop_status=1 and status=1 and lock_state=0 and delete_time is NULL LIMIT 1 SELECT id FROM llxz_product.ct_product WHERE audit_state = 0 LIMIT 1 select * from llxz_product.ct_product where id=5270
-- 同城店铺 SELECT * FROM llxz_product.`ct_shop_invite_code_usage` SELECT * FROM llxz_product.ct_shop WHERE status IN (3) LIMIT 1
-- 订单使用的券信息 SELECT * FROM `llxz_order`.`ct_order_by_stages_discount` where order_id='008OI202512101998640572422938624T'
-- 九州品盾表 saas_charge 这个是等级 risk_type 这个是分数 select * from llxz_components.ct_pindun_fllock SELECT create_time,saas_charge AS 等级,risk_type AS 分数 FROM llxz_components.ct_pindun_fllock ORDER BY create_time DESC
-- 租后管理已分配订单表 select * from llxz_order.ct_debt_collection_manage_order where order_id='008OI202505291927987776159092736'
select * from llxz_order.ct_action_audit where order_id='008OI202509121966401215316840448'
-- 店铺周报sql -- '订单状态 01:待支付 02:支付中 03:已支付申请关单 04:待发货 05:待确认收货 06:租用中 07:待结算 08:结算待支付 09:订单完成 10:交易关闭 12待归还 13下单待审核 14申请取消 15商家关单' -- 统计上周一0点到周末59分59秒店铺=71008738021cd3393bacbac182bd6a86af0b5c87店铺的订单数 SELECT * FROM llxz_order.ct_user_orders WHERE shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' AND create_time >= CURDATE() - INTERVAL (WEEKDAY(CURDATE()) + 7) DAY AND create_time < CURDATE() - INTERVAL WEEKDAY(CURDATE()) DAY AND delete_time IS NULL AND rent_start IS NOT NULL -- AND quick_order = 0 -- 0代表私域 AND quick_order IS NOT NULL -- 确保不为空 AND quick_order != 0; -- 非0代表公域 -- AND status IN ('05', '06', '07', '08', '09', '12', '16') -- AND user_name='章煜' ORDER BY create_time DESC;
-- 上上周数据 SELECT * FROM llxz_order.ct_user_orders WHERE shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' -- 上上周一 00:00:00 AND create_time >= CURDATE() - INTERVAL (WEEKDAY(CURDATE()) + 14) DAY -- 上上周日 23:59:59.999 AND create_time < CURDATE() - INTERVAL (WEEKDAY(CURDATE()) + 7) DAY AND delete_time IS NULL -- 根据需要取消注释以下条件 -- AND rent_start IS NOT NULL -- AND quick_order = 0 -- 0代表私域 -- AND quick_order IS NOT NULL -- 确保不为空 -- AND quick_order != 0; -- 非0代表公域 -- AND status IN ('05', '06', '07', '08', '09', '12', '16') -- AND user_name='章煜' ORDER BY create_time DESC;
select CASE WHEN (uo.quick_order is null OR uo.quick_order = '' OR uo.quick_order = '0') THEN '私域' ELSE '公域' END as domain, count(distinct obs.order_id) as count from ct_order_by_stages obs join ct_user_orders uo on obs.order_id = uo.order_id where uo.shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' and uo.create_time >= '2025-11-20 00:00:00' and uo.create_time <= '2025-11-20 23:59:59' and uo.delete_time is null and obs.create_time >= '2025-11-19 00:00:00' and obs.total_rent > 0 and obs.status in ('2', '3', '7') group by domain;
SELECT order_id FROM llxz_order.ct_user_orders WHERE shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' AND channel_id IN ('004', '007', '008', '009', '011', '012', '085') AND channel_provenance != 6 AND channel_provenance != 8 AND status='06' ORDER BY create_time DESC LIMIT 1;
SELECT o.order_id FROM llxz_order.ct_user_orders o WHERE o.shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' AND o.channel_id IN ('004', '007', '008', '009', '011', '012', '085') AND o.channel_provenance NOT IN (6, 8) AND o.status = '06' AND NOT EXISTS ( SELECT 1 FROM llxz_order.ct_shop_order_complete_apply_log l WHERE l.order_id = o.order_id ) ORDER BY o.create_time DESC LIMIT 1;
SELECT COUNT(*) as total_count FROM llxz_order.ct_user_orders WHERE shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' AND channel_id IN ('004', '007', '008', '009', '011', '012', '085') AND rent_start IS NOT NULL AND (delete_time IS NULL OR delete_time <= '2001-01-01 00:00:00') AND status IN ('06') AND unrent_time < NOW();
select total_rent,status from llxz_order.ct_order_by_stages where order_id = (SELECT order_id FROM llxz_order.ct_user_orders WHERE shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87' AND channel_provenance != 6 AND channel_provenance != 8 ORDER BY create_time DESC LIMIT 1) LIMIT 1
WITH order_counts AS ( SELECT order_id, COUNT(*) OVER (PARTITION BY order_id) as stage_count, ROW_NUMBER() OVER (PARTITION BY order_id ORDER BY create_time DESC) as rn FROM llxz_order.ct_order_by_stages WHERE shop_id = '71008738021cd3393bacbac182bd6a86af0b5c87') SELECT order_id FROM order_counts WHERE stage_count > 1 AND rn = 1 LIMIT 1;
